import{_ as e,o as r,c as l,a1 as t}from"./chunks/framework.DjAWjfpz.js";const c=JSON.parse('{"title":"Font Plus (更多字体设置)","description":"","frontmatter":{},"headers":[],"relativePath":"amll-plugins/font-plus.md","filePath":"amll-plugins/font-plus.md"}'),o={name:"amll-plugins/font-plus.md"};function h(i,a,n,s,d,u){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="font-plus-更多字体设置" tabindex="-1">Font Plus (更多字体设置) <a class="header-anchor" href="#font-plus-更多字体设置" aria-label="Permalink to &quot;Font Plus (更多字体设置)&quot;">​</a></h1><p>为 AMLL Player 进一步提供了更加精细的字体设置。</p><h2 id="下载" tabindex="-1">下载 <a class="header-anchor" href="#下载" aria-label="Permalink to &quot;下载&quot;">​</a></h2><ul><li>从 <a href="https://github.com/ranhengzhang/amll-player-font-plus/actions/workflows/auto-build.yml" target="_blank" rel="noreferrer">Github Actions</a> 页面下载自动构建的结果；</li><li>克隆 <a href="https://github.com/ranhengzhang/amll-player-font-plus" target="_blank" rel="noreferrer">仓库</a> 到本地之后，执行 <code>pnpm i &amp; pnpm build</code> 命令。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><p>将 <code>.js</code> 文件复制到 AMLL Player 插件文件夹中，重启 AMLL Player。</p><h2 id="功能" tabindex="-1">功能 <a class="header-anchor" href="#功能" aria-label="Permalink to &quot;功能&quot;">​</a></h2><h3 id="歌曲信息部分设置" tabindex="-1">歌曲信息部分设置 <a class="header-anchor" href="#歌曲信息部分设置" aria-label="Permalink to &quot;歌曲信息部分设置&quot;">​</a></h3><h4 id="标题字体" tabindex="-1">标题字体 <a class="header-anchor" href="#标题字体" aria-label="Permalink to &quot;标题字体&quot;">​</a></h4><p>设置标题的字体家族，覆盖AMLL Player 设置的字体。</p><h4 id="标题大小" tabindex="-1">标题大小 <a class="header-anchor" href="#标题大小" aria-label="Permalink to &quot;标题大小&quot;">​</a></h4><p>设置标题的字体大小，单位符合CSS要求即可。</p><h4 id="启用粗体标题" tabindex="-1">启用粗体标题 <a class="header-anchor" href="#启用粗体标题" aria-label="Permalink to &quot;启用粗体标题&quot;">​</a></h4><p>默认情况下AMLL Player会将标题字体加粗，此项默认打开，关闭以显示AMLL Player 设置中的字重。</p><h3 id="逐字歌词部分设置" tabindex="-1">逐字歌词部分设置 <a class="header-anchor" href="#逐字歌词部分设置" aria-label="Permalink to &quot;逐字歌词部分设置&quot;">​</a></h3><h4 id="清除元数据行效果" tabindex="-1">清除元数据行效果 <a class="header-anchor" href="#清除元数据行效果" aria-label="Permalink to &quot;清除元数据行效果&quot;">​</a></h4><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>私用效果，在歌词中添加无时间轴的一行显示自定义内容。</p></div><p>为元数据行清理掉字体等效果。</p><h4 id="修复原文行高" tabindex="-1">修复原文行高 <a class="header-anchor" href="#修复原文行高" aria-label="Permalink to &quot;修复原文行高&quot;">​</a></h4><p>在某些字体中，原文的 &quot;fgy&quot; 等字母下方显示不全，该选项增加行高保证这些字母也能显示完全。</p><h4 id="主唱行字体大小" tabindex="-1">主唱行字体大小 <a class="header-anchor" href="#主唱行字体大小" aria-label="Permalink to &quot;主唱行字体大小&quot;">​</a></h4><p>该选项设置主行字体大小。</p><h4 id="背景行字体大小" tabindex="-1">背景行字体大小 <a class="header-anchor" href="#背景行字体大小" aria-label="Permalink to &quot;背景行字体大小&quot;">​</a></h4><p>该选项设置背景行字体大小。</p><h4 id="背景行翻-音译行缩放" tabindex="-1">背景行翻/音译行缩放 <a class="header-anchor" href="#背景行翻-音译行缩放" aria-label="Permalink to &quot;背景行翻/音译行缩放&quot;">​</a></h4><p>该选项设置背景行相对于主行的缩放系数。</p><h4 id="特殊语言字体" tabindex="-1">特殊语言字体 <a class="header-anchor" href="#特殊语言字体" aria-label="Permalink to &quot;特殊语言字体&quot;">​</a></h4><p>当歌词行同时有翻译和音译时显示的字体。</p><h4 id="特殊语言中的空格宽度" tabindex="-1">特殊语言中的空格宽度 <a class="header-anchor" href="#特殊语言中的空格宽度" aria-label="Permalink to &quot;特殊语言中的空格宽度&quot;">​</a></h4><p>当歌词行同时有翻译和音译时的空格宽度，加宽可用于区分字体留空和空格宽度。</p><h4 id="扩展到所有语言" tabindex="-1">扩展到所有语言 <a class="header-anchor" href="#扩展到所有语言" aria-label="Permalink to &quot;扩展到所有语言&quot;">​</a></h4><p>将空格宽度应用到所有情况，即使没有音译或翻译。</p><h4 id="翻译行字体" tabindex="-1">翻译行字体 <a class="header-anchor" href="#翻译行字体" aria-label="Permalink to &quot;翻译行字体&quot;">​</a></h4><p>该选项设置翻译行字体家族。</p><h4 id="翻译行字号" tabindex="-1">翻译行字号 <a class="header-anchor" href="#翻译行字号" aria-label="Permalink to &quot;翻译行字号&quot;">​</a></h4><p>该选项设置翻译行字体大小。单位符合CSS要求即可。</p><h4 id="音译行字体" tabindex="-1">音译行字体 <a class="header-anchor" href="#音译行字体" aria-label="Permalink to &quot;音译行字体&quot;">​</a></h4><p>该选项设置音译行字体家族。</p><h4 id="音译行字号" tabindex="-1">音译行字号 <a class="header-anchor" href="#音译行字号" aria-label="Permalink to &quot;音译行字号&quot;">​</a></h4><p>该选项设置音译行字体大小。单位符合CSS要求即可。</p><h4 id="ruby-字体" tabindex="-1">Ruby 字体 <a class="header-anchor" href="#ruby-字体" aria-label="Permalink to &quot;Ruby 字体&quot;">​</a></h4><p>该选项设置 Ruby 部分字体家族。</p>',42)])])}const b=e(o,[["render",h]]);export{c as __pageData,b as default};
